// 入口：openChatSettings()（当前私聊设置）/ openGlobalMessageSettings()（消息全局默认设置）。
// 依赖：core/storage.js, core/storage-keys.js, core/ui.js, core/events.js, core/util.js,
//       core/ai-client.js, ./index.js, ./shared-utils.js
// 红线：图标只准 SVG 线稿 1.5px stroke；视觉值全部走 CSS 变量；禁止任何 emoji 字符；
//       所有功能真实实现，禁止假按钮、占位逻辑；繁琐分组用折叠卡（小抽屉）；弹窗文案可爱。

import { KEYS, STORES } from '../../core/storage-keys.js';
import { getData, setData, getDB, setDB, deleteDB, getAllDB, generateId, getNow } from '../../core/storage.js';
import {
  showToast, showConfirm,
  createIcon, registerIcon, createCollapsibleCard
} from '../../core/ui.js';
import bus from '../../core/events.js';
import {
  injectStyle, clamp, debounce, downloadBlob,
  isUsableImage, cssUrl, pickImageFile, compressImage
} from '../../core/util.js';
import { getAIConfig, saveAIConfig, isAIConfigured, chatOnce } from '../../core/ai-client.js';
import { getState, render, backToSessionList, applySessionWallpaper } from './index.js';
import { escapeHTML } from './shared-utils.js';

