// ════════════════════════════════════════
// CSS 注入（全 CSS 变量，主题变了我也跟着变）
// ════════════════════════════════════════

let cssInjected = false;
function ensureCSS() {
  if (cssInjected) return;
  cssInjected = true;
  injectStyle('app-chat-settings-style', `
    /* 推入式全屏覆盖层：从右侧滑入，弹性曲线 */
    .chat-settings-overlay{
      position:absolute; inset:0; z-index:60;
      background:var(--bg-primary);
      display:flex; flex-direction:column;
      transform:translateX(100%);
      transition:transform 280ms var(--motion-spring, cubic-bezier(0.34,1.56,0.64,1));
      overflow:hidden;
    }
    .chat-settings-overlay.show{ transform:translateX(0); }
    .chat-settings-overlay.leaving{
      transform:translateX(100%);
      transition:transform 220ms var(--motion, ease);
    }

    /* 头部：返回按钮 + 标题 + 占位 */
    .chat-settings-header{
      flex-shrink:0; display:flex; align-items:center; gap:8px;
      padding:calc(env(safe-area-inset-top,0px) + 10px) 12px 10px;
      background:color-mix(in srgb, var(--bg-card) 92%, transparent);
      backdrop-filter:blur(var(--glass-blur, 8px));
      -webkit-backdrop-filter:blur(var(--glass-blur, 8px));
      border-bottom:1px solid color-mix(in srgb, var(--text-hint) 16%, transparent);
    }
    .chat-settings-back{
      width:36px; height:36px; border-radius:50%; border:none; cursor:pointer;
      background:transparent; color:var(--text-secondary);
      display:flex; align-items:center; justify-content:center;
      transition:var(--motion, 200ms ease);
    }
    .chat-settings-back:active{
      transform:scale(var(--press-scale, 0.94));
      background:color-mix(in srgb, var(--accent-light, var(--accent)) 40%, transparent);
    }
    .chat-settings-title{
      flex:1; font-size:var(--font-size-title, 18px); font-weight:600;
      color:var(--text-primary); text-align:center;
    }
    .chat-settings-spacer{ width:36px; flex-shrink:0; }

    /* 滚动主体 */
    .chat-settings-body{
      flex:1; overflow-y:auto; -webkit-overflow-scrolling:touch;
      padding:14px 12px calc(env(safe-area-inset-bottom,0px) + 28px);
    }

    /* 折叠卡头部图标 */
    .cs-card-icon{
      color:var(--accent-dark, var(--accent)); display:inline-flex;
      margin-right:6px; flex-shrink:0;
    }
    .collapsible-header .collapsible-title{
      display:flex; align-items:center;
    }

    /* ── 字段容器 ── */
    .cs-field{ display:flex; flex-direction:column; gap:6px; margin-bottom:14px; }
    .cs-field:last-child{ margin-bottom:0; }
    .cs-field-label{
      font-size:var(--font-size-small, 13px); color:var(--text-secondary);
      display:flex; align-items:center; gap:6px;
    }
    .cs-field-hint{ font-size:var(--font-size-caption, 12px); color:var(--text-hint); line-height:1.5; }

    /* ── 行控件（左标签右控件）── */
    .cs-row{
      display:flex; align-items:center; gap:12px;
      padding:12px 0;
      border-bottom:1px solid color-mix(in srgb, var(--text-hint) 10%, transparent);
    }
    .cs-row:last-child{ border-bottom:none; }
    .cs-row-label{
      flex:1; display:flex; flex-direction:column; gap:2px; min-width:0;
    }
    .cs-row-title{
      font-size:var(--font-size-base, 15px); color:var(--text-primary);
      display:flex; align-items:center; gap:8px;
    }
    .cs-row-hint{ font-size:var(--font-size-caption, 12px); color:var(--text-hint); line-height:1.4; }
    .cs-row.danger .cs-row-title{ color:var(--danger, #e53935); }
    .cs-row.danger .cs-row-hint{ color:color-mix(in srgb, var(--danger, #e53935) 80%, transparent); }

    /* ── Toggle 开关 ── */
    .cs-toggle{
      position:relative; width:46px; height:26px; border-radius:999px;
      background:color-mix(in srgb, var(--text-hint) 35%, transparent);
      border:none; cursor:pointer; flex-shrink:0;
      transition:background var(--motion, 200ms ease);
    }
    .cs-toggle::after{
      content:''; position:absolute; top:3px; left:3px;
      width:20px; height:20px; border-radius:50%; background:var(--bg-card, #fff);
      box-shadow:var(--shadow-sm, 0 1px 3px rgba(0,0,0,0.12));
      transition:transform var(--motion, 200ms ease) var(--motion-spring, cubic-bezier(0.34,1.56,0.64,1));
    }
    .cs-toggle.on{ background:var(--accent); }
    .cs-toggle.on::after{ transform:translateX(20px); }
    .cs-toggle:active::after{ transform:scale(0.92); }
    .cs-toggle.on:active::after{ transform:translateX(20px) scale(0.92); }

    /* ── Segmented 分段选择 ── */
    .cs-seg{
      display:inline-flex; padding:3px; border-radius:var(--radius-md, 10px);
      background:color-mix(in srgb, var(--text-hint) 18%, transparent);
      gap:2px; flex-shrink:0;
    }
    .cs-seg-item{
      padding:7px 14px; border-radius:calc(var(--radius-md, 10px) - 3px);
      border:none; cursor:pointer; background:transparent;
      color:var(--text-secondary); font-size:var(--font-size-small, 13px); font-family:inherit;
      transition:var(--motion, 200ms ease);
      display:inline-flex; align-items:center; gap:5px;
    }
    .cs-seg-item:active{ transform:scale(var(--press-scale, 0.94)); }
    .cs-seg-item.active{
      background:var(--bg-card, #fff); color:var(--accent-dark, var(--accent));
      box-shadow:var(--shadow-sm, 0 1px 3px rgba(0,0,0,0.12)); font-weight:600;
    }
    .cs-seg.cs-seg-block{ display:flex; width:100%; }
    .cs-seg.cs-seg-block .cs-seg-item{ flex:1; justify-content:center; }

    /* ── Slider 滑块 ── */
    .cs-slider{
      -webkit-appearance:none; appearance:none;
      width:100%; height:6px; border-radius:3px;
      background:color-mix(in srgb, var(--text-hint) 25%, transparent);
      outline:none; cursor:pointer;
    }
    .cs-slider::-webkit-slider-thumb{
      -webkit-appearance:none; appearance:none;
      width:22px; height:22px; border-radius:50%;
      background:var(--accent); border:3px solid var(--bg-card, #fff);
      box-shadow:var(--shadow-sm, 0 1px 3px rgba(0,0,0,0.12)); cursor:pointer;
      transition:transform var(--motion, 200ms ease);
    }
    .cs-slider::-webkit-slider-thumb:active{ transform:scale(1.15); }
    .cs-slider::-moz-range-thumb{
      width:22px; height:22px; border-radius:50%;
      background:var(--accent); border:3px solid var(--bg-card, #fff);
      box-shadow:var(--shadow-sm, 0 1px 3px rgba(0,0,0,0.12)); cursor:pointer;
    }
    .cs-slider-row{ display:flex; align-items:center; gap:10px; min-width:160px; }
    .cs-slider-val{
      font-size:var(--font-size-small, 13px); color:var(--accent-dark, var(--accent));
      font-weight:600; min-width:42px; text-align:right; flex-shrink:0;
    }

    /* ── 输入框 / 文本域 ── */
    .cs-input, .cs-textarea{
      width:100%; padding:10px 12px;
      border:1px solid color-mix(in srgb, var(--text-hint) 22%, transparent);
      border-radius:var(--radius-md, 10px);
      background:var(--bg-secondary, var(--bg-card, #fff));
      color:var(--text-primary); font-size:var(--font-size-base, 15px); font-family:inherit;
      outline:none; transition:border-color var(--motion, 200ms ease);
    }
    .cs-input:focus, .cs-textarea:focus{ border-color:var(--accent); }
    .cs-input::placeholder, .cs-textarea::placeholder{ color:var(--text-hint); }
    .cs-textarea{ resize:vertical; line-height:1.5; }
    .cs-input-row{ display:flex; align-items:center; gap:8px; }
    .cs-input-row .cs-input{ flex:1; }
    .cs-input-suffix-btn{
      width:40px; height:40px; border-radius:var(--radius-md, 10px);
      border:1px solid color-mix(in srgb, var(--text-hint) 22%, transparent);
      background:var(--bg-secondary, var(--bg-card, #fff)); color:var(--text-secondary);
      cursor:pointer; flex-shrink:0;
      display:flex; align-items:center; justify-content:center;
      transition:var(--motion, 200ms ease);
    }
    .cs-input-suffix-btn:active{ transform:scale(var(--press-scale, 0.94)); }

    /* ── 按钮 ── */
    .cs-btn{
      display:inline-flex; align-items:center; justify-content:center; gap:6px;
      padding:10px 16px; border-radius:var(--radius-md, 10px);
      border:none; cursor:pointer; font-size:var(--font-size-base, 15px); font-family:inherit;
      transition:var(--motion, 200ms ease);
    }
    .cs-btn:active{ transform:scale(var(--press-scale, 0.94)); }
    .cs-btn:disabled{ opacity:0.5; cursor:not-allowed; }
    .cs-btn-primary{ background:var(--accent); color:var(--bubble-user-text, #fff); font-weight:500; }
    .cs-btn-ghost{
      background:color-mix(in srgb, var(--accent-light, var(--accent)) 25%, transparent);
      color:var(--accent-dark, var(--accent));
    }
    .cs-btn-block{ display:flex; width:100%; }
    .cs-btn.loading{ pointer-events:none; opacity:0.7; }
    .cs-btn.loading::after{
      content:''; display:inline-block; width:14px; height:14px;
      border:2px solid currentColor; border-top-color:transparent;
      border-radius:50%; animation:csSpin 0.7s linear infinite;
    }
    @keyframes csSpin{ to{ transform:rotate(360deg); } }

    /* ── 测试连接结果 ── */
    .cs-test-result{
      margin-top:10px; padding:10px 12px; border-radius:var(--radius-md, 10px);
      font-size:var(--font-size-small, 13px); line-height:1.5;
      white-space:pre-wrap; display:none;
    }
    .cs-test-result.show{ display:block; }
    .cs-test-result.ok{
      background:color-mix(in srgb, var(--accent) 12%, transparent);
      color:var(--accent-dark, var(--accent));
    }
    .cs-test-result.err{
      background:color-mix(in srgb, var(--danger, #e53935) 12%, transparent);
      color:var(--danger, #e53935);
    }

    /* ── 对方资料卡 ── */
    .cs-profile{
      display:flex; gap:14px; padding:14px;
      border-radius:var(--radius-lg, 14px);
      background:color-mix(in srgb, var(--accent) 6%, var(--bg-card, #fff));
      margin-bottom:14px;
    }
    .cs-profile-avatar{
      width:60px; height:60px; border-radius:50%; flex-shrink:0;
      overflow:hidden; background:color-mix(in srgb, var(--text-hint) 15%, transparent);
      display:flex; align-items:center; justify-content:center;
      color:var(--text-hint);
    }
    .cs-profile-avatar-img{
      width:100%; height:100%; background-size:cover; background-position:center;
    }
    .cs-profile-info{ flex:1; min-width:0; display:flex; flex-direction:column; gap:3px; }
    .cs-profile-name{
      font-size:var(--font-size-title, 18px); font-weight:600;
      color:var(--text-primary);
    }
    .cs-profile-nick{ font-size:var(--font-size-small, 13px); color:var(--text-secondary); }
    .cs-profile-meta{ font-size:var(--font-size-caption, 12px); color:var(--text-hint); line-height:1.4; }
    .cs-info-grid{ display:flex; flex-direction:column; gap:10px; }
    .cs-info-item{
      padding:10px 12px; border-radius:var(--radius-md, 10px);
      background:var(--bg-secondary, var(--bg-card, #fff));
    }
    .cs-info-item-label{
      font-size:var(--font-size-caption, 12px); color:var(--text-hint);
      display:flex; align-items:center; gap:5px; margin-bottom:4px;
    }
    .cs-info-item-value{
      font-size:var(--font-size-small, 13px); color:var(--text-primary); line-height:1.5;
      word-break:break-word;
    }
    .cs-info-item-value.empty{ color:var(--text-hint); }

    /* ── 聊天背景预览 ── */
    .cs-wp-preview{
      width:100%; height:120px; border-radius:var(--radius-lg, 14px);
      background-size:cover; background-position:center;
      background-color:var(--bg-secondary, var(--bg-card, #fff));
      margin-bottom:12px; position:relative; overflow:hidden;
      border:1px solid color-mix(in srgb, var(--text-hint) 14%, transparent);
    }
    .cs-wp-preview-empty{
      position:absolute; inset:0; display:flex; flex-direction:column;
      align-items:center; justify-content:center; gap:8px;
      color:var(--text-hint); font-size:var(--font-size-small, 13px);
    }
    .cs-wp-actions{ display:flex; gap:10px; margin-top:6px; }
    .cs-wp-actions .cs-btn{ flex:1; }

    /* ── 分组提示 ── */
    .cs-section-hint{
      font-size:var(--font-size-caption, 12px); color:var(--text-hint);
      line-height:1.5; padding:8px 4px;
    }

    /* ── 危险按钮 ── */
    .cs-btn-danger{
      background:color-mix(in srgb, var(--danger, #e53935) 12%, transparent);
      color:var(--danger, #e53935);
    }
    .cs-btn-danger:active{ background:color-mix(in srgb, var(--danger, #e53935) 20%, transparent); }

    @media (prefers-reduced-motion:reduce){
      .chat-settings-overlay, .cs-toggle, .cs-seg-item, .cs-slider,
      .cs-btn, .cs-input, .cs-textarea{
        transition-duration:0.01ms!important;
      }
    }
  `);
}

// ════════════════════════════════════════
// 控件工厂（统一构造，全部走 CSS 变量）
// ═════════════════════════